    seed: "mini",
    createdAt: "2026-06-12T00:00:00.000Z",
    runId: "mini",
  },
  turns,
});

describe("trace summarizer", () => {
  it("extracts known facts from a hand-built aggressive mini-trace", () => {
    const trace = miniTrace([
      {
        turn: 1,
        action: { kind: "attack", targetId: "enemy#1" },
        events: [
          {
            turn: 0,
            type: "attack_hit",
